Perplexity is a measure of how well a language model predicts a test set. The lower the perplexity, the better the model is at predicting the test set.

Here's an example of how you can modify a basic language model to compute the perplexity of a test set:

```python
import math
from collections import Counter

class LanguageModel:
    def __init__(self, train_data):
        self.train_data = train_data
        self.word_counts = self._count_words()

    def _count_words(self):
        word_counts = Counter()
        for sentence in self.train_data:
            for word in sentence:
                word_counts[word] += 1
        return word_counts

    def _calculate_probability(self, word):
        total_words = sum(self.word_counts.values())
        return self.word_counts[word] / total_words

    def perplexity(self, test_data):
        total_words = 0
        total_probability = 0
        for sentence in test_data:
            for word in sentence:
                total_words += 1
                probability = self._calculate_probability(word)
                total_probability -= math.log2(probability)
        return 2 ** (total_probability / total_words)

